import React, { useState, useEffect, useCallback } from 'react';
import TableTemplate from '../components/TableTemplate';
import FormTemplate from '../components/FormTemplate';
import SearchComponent from '../components/SearchComponent';
import { authorityService } from '../api/authorityService'; // *** Change this for other pages ***

function AuthorityPage() {
  const service = authorityService;

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [currentEntity, setCurrentEntity] = useState(service.initialFormState);
  const [currentId, setCurrentId] = useState(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const records = await service.getAll();
      setData(records);
    } catch (err) {
      setError(`Failed to fetch ${service.name} data.`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [service]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleSave = async (formData, isEditMode, id) => {
    try {
      // Validate Works_Under field - it must be null or reference an existing Authority_ID
      if (formData.Works_Under && formData.Works_Under !== '') {
        const supervisorExists = data.some(authority => 
          authority.Authority_ID === parseInt(formData.Works_Under)
        );
        if (!supervisorExists) {
          setError(`Supervisor ID ${formData.Works_Under} does not exist. Please enter a valid Authority ID or leave empty.`);
          return;
        }
      }

      setError(null); // Clear any previous errors

      if (isEditMode) {
        await service.update(id, formData);
      } else {
        await service.add(formData); 
      }
      fetchData(); 
      handleCancelEdit();
    } catch (err) {
      let errorMessage = `Failed to ${isEditMode ? 'update' : 'add'} ${service.name} record.`;

      // Check for specific database constraint errors
      if (err.response?.data?.message) {
        if (err.response.data.message.includes('foreign key constraint')) {
          errorMessage = `Invalid Supervisor ID. The Works_Under field must reference an existing Authority ID or be empty.`;
        } else {
          errorMessage = err.response.data.message;
        }
      } else if (err.message) {
        errorMessage = err.message;
      }

      setError(errorMessage);
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(`Are you sure you want to delete ${service.name} ID ${id}?`)) return;
    try {
      await service.remove(id);
      fetchData();
    } catch (err) {
      setError(`Failed to delete ${service.name} record. Check for dependent records.`);
      console.error(err);
    }
  };

  const handleEdit = (item) => {
    setIsEditing(true);

    // Date formatting for fields like Installation_Date in Bin
    let itemData = { ...item };
    if (itemData.Installation_Date) {
      // Assuming ISO string from backend, convert to YYYY-MM-DD for date input type
      itemData.Installation_Date = new Date(itemData.Installation_Date).toISOString().split('T')[0];
    }

    setCurrentEntity(itemData);
    setCurrentId(item[service.entityIdKey]);
  };

  const handleCancelEdit = () => {
      setIsEditing(false);
      setCurrentEntity(service.initialFormState);
      setCurrentId(null);
  };

      const pageStyles = {
        background: 'rgba(255, 255, 255, 0.95)',
        backdropFilter: 'blur(20px)',
        borderRadius: '24px',
        padding: '40px',
        margin: '20px 0',
        boxShadow: '0 20px 60px rgba(17, 153, 142, 0.2), 0 10px 30px rgba(17, 153, 142, 0.1)',
        border: '2px solid rgba(17, 153, 142, 0.2)',
        position: 'relative',
        overflow: 'hidden',
      };

      const headerStyles = {
        textAlign: 'center',
        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        fontSize: '3rem',
        fontWeight: '800',
        marginBottom: '30px',
        textShadow: 'none',
        borderBottom: '4px solid transparent',
        borderImage: 'linear-gradient(90deg, #11998e, #38ef7d) 1',
        paddingBottom: '20px',
        letterSpacing: '0.5px',
      };

  const errorStyles = {
    background: 'linear-gradient(135deg, #e74c3c, #c0392b)',
    color: 'white',
    padding: '15px 25px',
    borderRadius: '16px',
    marginBottom: '25px',
    boxShadow: '0 8px 25px rgba(231, 76, 60, 0.4)',
    border: 'none',
    fontSize: '1rem',
    fontWeight: '600',
    animation: 'shake 0.5s ease',
  };

  const loadingStyles = {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '300px',
    fontSize: '1.5rem',
    color: '#11998e',
    fontWeight: '600',
  };

  if (loading) return (
    <div style={pageStyles}>
      <div style={loadingStyles}>
        <div style={{ textAlign: 'center' }}>
          <div className="loading-spinner" style={{ margin: '0 auto 20px' }}></div>
          <div style={{ fontSize: '1.3rem', fontWeight: '600', color: '#11998e' }}>Loading {service.name} data...</div>
        </div>
      </div>
    </div>
  );

  return (
    <div style={pageStyles}>
      <div style={headerStyles}>
        <div style={{ fontSize: '4rem', marginBottom: '15px' }}>🏛️</div>
        <h2 style={{ margin: 0, fontSize: 'inherit', fontWeight: 'inherit' }}>{service.name}</h2>
        <p style={{ margin: '10px 0 0 0', fontSize: '1rem', color: '#11998e', opacity: 0.8 }}>Regulatory oversight and environmental compliance</p>
      </div>
      {error && <div style={errorStyles}>⚠️ Error: {error}</div>}

      <SearchComponent 
          entityName={service.name} 
          entityIdKey={service.entityIdKey}
          onSearch={service.getOne} 
          onEdit={handleEdit}
          onDelete={handleDelete}
      />

      <FormTemplate
        fields={service.fields}
        initialData={currentEntity}
        onSave={handleSave}
        isEditing={isEditing}
        entityId={currentId}
        onCancelEdit={handleCancelEdit}
      />

      <h3 style={{ 
        fontSize: '1.8rem', 
        fontWeight: '700', 
        textAlign: 'center', 
        marginTop: '30px', 
        marginBottom: '25px',
        background: 'linear-gradient(135deg, #11998e 0%, #38ef7d 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text'
      }}>📋 All {service.name} Records</h3>
      <TableTemplate
        data={data}
        columns={service.columns}
        entityIdKey={service.entityIdKey}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
    </div>
  );
}

export default AuthorityPage;
